import { useCallback, useEffect, useRef } from 'react';
import {
  getGenerationDropData,
  getMultiGenerationDropData,
  getDragType,
  type GenerationDropData,
} from '@/shared/lib/dnd/dragDrop';
import { inferDragKind } from '@/tools/video-editor/lib/drop-position';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { UseAssetManagementResult } from '@/tools/video-editor/hooks/useAssetManagement';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData.types';
import {
  createEffectLayerClipMeta,
  getNextClipId,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { TrackKind } from '@/tools/video-editor/types';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import { createAutoScroller } from '@/tools/video-editor/lib/auto-scroll';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';

type TimelineDropPosition = NonNullable<ReturnType<DragCoordinator['update']>>;

function isGenerationDragType(dragType: ReturnType<typeof getDragType>) {
  return dragType === 'generation' || dragType === 'generation-multi';
}

function isVideoGeneration(data: GenerationDropData): boolean {
  const contentType = typeof data.metadata?.content_type === 'string'
    ? data.metadata.content_type
    : null;

  return contentType?.startsWith('video/')
    || data.variantType === 'video'
    || /\.(mp4|mov|webm|m4v)$/i.test(data.imageUrl);
}

function readPositiveNumber(value: unknown): number | null {
  return typeof value === 'number' && Number.isFinite(value) && value > 0 ? value : null;
}

function getDroppedGenerationDuration(data: GenerationDropData): number {
  if (!isVideoGeneration(data)) {
    return 5;
  }

  return readPositiveNumber(data.metadata?.duration)
    ?? readPositiveNumber(data.metadata?.duration_seconds)
    ?? readPositiveNumber(data.metadata?.original_duration)
    ?? 5;
}

function createTrack(
  dataRef: React.MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  insertAtTop: boolean,
  label?: string,
): { trackId: string; insertAtTop: boolean } | null {
  const current = dataRef.current;
  if (!current) {
    return null;
  }

  const prefix = kind === 'audio' ? 'A' : 'V';
  const nextNumber = getTrackIndex(current.tracks, prefix) + 1;
  const trackId = `${prefix}${nextNumber}`;
  const nextTrack = { id: trackId, kind, label: label ?? trackId };
  const nextRow = { id: trackId, actions: [] };

  dataRef.current = {
    ...current,
    tracks: insertAtTop ? [nextTrack, ...current.tracks] : [...current.tracks, nextTrack],
    rows: insertAtTop ? [nextRow, ...current.rows] : [...current.rows, nextRow],
  };

  return { trackId, insertAtTop };
}

function createTrackAtTop(
  dataRef: React.MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  label?: string,
): { trackId: string; insertAtTop: true } | null {
  const createdTrack = createTrack(dataRef, kind, true, label);
  return createdTrack ? { ...createdTrack, insertAtTop: true } : null;
}

function createTrackForDrop(
  dataRef: React.MutableRefObject<TimelineData | null>,
  kind: 'audio' | 'visual',
  insertAtTop: boolean,
  label?: string,
): { trackId: string; insertAtTop: boolean } | null {
  return insertAtTop
    ? createTrackAtTop(dataRef, kind, label)
    : createTrack(dataRef, kind, false, label);
}

function removeAction(rows: TimelineData['rows'], actionId: string) {
  return rows.map((row) => ({
    ...row,
    actions: row.actions.filter((action) => action.id !== actionId),
  }));
}

function inferFileDropKind(file: File): TrackKind {
  const extension = file.name.slice(file.name.lastIndexOf('.')).toLowerCase();
  return ['.mp3', '.wav', '.aac', '.m4a'].includes(extension) ? 'audio' : 'visual';
}

function isImageFile(file: File): boolean {
  const extension = file.name.slice(file.name.lastIndexOf('.')).toLowerCase();
  return file.type.startsWith('image/')
    || ['.png', '.jpg', '.jpeg', '.webp', '.gif', '.bmp', '.avif'].includes(extension);
}

function handleTextToolDrop({
  dataRef,
  dropPosition,
  insertAtTop,
  handleAddTextAt,
}: {
  dataRef: React.MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  handleAddTextAt?: (trackId: string, time: number) => void;
}): boolean {
  if (!handleAddTextAt || !dataRef.current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
  if (!targetTrackId) {
    targetTrackId = createTrackForDrop(dataRef, 'visual', insertAtTop)?.trackId;
  }

  if (!targetTrackId) {
    return true;
  }

  handleAddTextAt(targetTrackId, dropPosition.time);
  return true;
}

function handleEffectLayerDrop({
  dataRef,
  dropPosition,
  insertAtTop,
  selectedTrackId,
  applyEdit,
}: {
  dataRef: React.MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  selectedTrackId: string | null;
  applyEdit: UseTimelineDataResult['applyEdit'];
}): boolean {
  let current = dataRef.current;
  if (!current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack
    ? null
    : getCompatibleTrackId(current.tracks, dropPosition.trackId, 'visual', selectedTrackId);

  if (!targetTrackId) {
    targetTrackId = createTrackForDrop(dataRef, 'visual', insertAtTop)?.trackId ?? null;
    current = dataRef.current;
  }

  if (!targetTrackId || !current) {
    return true;
  }

  const clipId = getNextClipId(current.meta);
  const clipMeta = createEffectLayerClipMeta(targetTrackId);
  const duration = clipMeta.hold ?? 5;
  const action: TimelineAction = {
    id: clipId,
    start: Math.max(0, dropPosition.time),
    end: Math.max(0, dropPosition.time) + duration,
    effectId: `effect-${clipId}`,
  };
  const rowsWithClip = current.rows.map((row) => (
    row.id === targetTrackId
      ? { ...row, actions: [...row.actions, action] }
      : row
  ));
  const { rows: nextRows, metaPatches, adjustments: _adjustments } = resolveOverlaps(
    rowsWithClip,
    targetTrackId,
    clipId,
    current.meta,
  );
  const resolvedAction = nextRows
    .find((row) => row.id === targetTrackId)
    ?.actions.find((candidate) => candidate.id === clipId);
  const nextClipOrder = updateClipOrder(current.clipOrder, targetTrackId, (ids) => [...ids, clipId]);

  applyEdit({
    type: 'rows',
    rows: nextRows,
    metaUpdates: {
      ...metaPatches,
      [clipId]: {
        ...clipMeta,
        hold: resolvedAction ? Math.max(0.05, resolvedAction.end - resolvedAction.start) : clipMeta.hold,
      },
    },
    clipOrderOverride: nextClipOrder,
  });
  return true;
}

async function handleFileDrop({
  files,
  dataRef,
  dropPosition,
  insertAtTop,
  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  registerGenerationAsset,
  uploadImageGeneration,
  dropAsset,
}: {
  files: File[];
  dataRef: React.MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  selectedTrackId: string | null;
  applyEdit: UseTimelineDataResult['applyEdit'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  uploadAsset: UseTimelineDataResult['uploadAsset'];
  invalidateAssetRegistry: UseTimelineDataResult['invalidateAssetRegistry'];
  resolveAssetUrl: (file: string) => Promise<string>;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
}): Promise<boolean> {
  if (!files.length || !dataRef.current) {
    return false;
  }

  const defaultClipDuration = 5;
  let timeOffset = 0;

  for (const file of files) {
    const kind = inferFileDropKind(file);
    let compatibleTrackId = dropPosition.isNewTrack
      ? null
      : getCompatibleTrackId(dataRef.current.tracks, dropPosition.trackId, kind, selectedTrackId);

    if (!compatibleTrackId) {
      compatibleTrackId = createTrackForDrop(dataRef, kind, insertAtTop)?.trackId ?? null;
    }

    if (!compatibleTrackId || !dataRef.current) {
      continue;
    }

    const clipTime = dropPosition.time + timeOffset;
    timeOffset += defaultClipDuration;

    const skeletonId = `uploading-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    const skeletonMeta: ClipMeta = {
      asset: `uploading:${file.name}`,
      track: compatibleTrackId,
      clipType: kind === 'audio' ? 'media' : 'hold',
      hold: kind === 'audio' ? undefined : defaultClipDuration,
      from: kind === 'audio' ? 0 : undefined,
      to: kind === 'audio' ? defaultClipDuration : undefined,
    };
    const skeletonAction: TimelineAction = {
      id: skeletonId,
      start: clipTime,
      end: clipTime + defaultClipDuration,
      effectId: `effect-${skeletonId}`,
    };

    const nextRows = dataRef.current.rows.map((row) =>
      row.id === compatibleTrackId
        ? { ...row, actions: [...row.actions, skeletonAction] }
        : row,
    );
    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [skeletonId]: skeletonMeta },
    }, { save: false });

    void (async () => {
      try {
        if (isImageFile(file)) {
          const generationData = await uploadImageGeneration(file);
          const current = dataRef.current;
          if (!current) {
            return;
          }

          applyEdit({
            type: 'rows',
            rows: removeAction(current.rows, skeletonId),
            metaDeletes: [skeletonId],
          });
          const assetId = registerGenerationAsset(generationData);
          if (assetId) {
            dropAsset(assetId, compatibleTrackId ?? undefined, clipTime);
          }
          return;
        }

        const result = await uploadAsset(file);
        const sourceUrl = await resolveAssetUrl(result.entry.file);
        patchRegistry(result.assetId, result.entry, sourceUrl);

        const current = dataRef.current;
        if (!current) {
          return;
        }

        applyEdit({
          type: 'rows',
          rows: removeAction(current.rows, skeletonId),
          metaDeletes: [skeletonId],
        });
        dropAsset(result.assetId, compatibleTrackId ?? undefined, clipTime);
        void invalidateAssetRegistry();
      } catch (error) {
        console.error('[drop] Upload failed:', error);
        const current = dataRef.current;
        if (!current) {
          return;
        }

        applyEdit({
          type: 'rows',
          rows: removeAction(current.rows, skeletonId),
          metaDeletes: [skeletonId],
        }, { save: false });
      }
    })();
  }

  return true;
}

function handleMultiGenerationDrop({
  generationItems,
  dataRef,
  dropPosition,
  insertAtTop,
  registerGenerationAsset,
  patchRegistry,
  dropAsset,
}: {
  generationItems: GenerationDropData[];
  dataRef: React.MutableRefObject<TimelineData | null>;
  dropPosition: TimelineDropPosition;
  insertAtTop: boolean;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
}): boolean {
  if (!generationItems.length || !dataRef.current) {
    return false;
  }

  let targetTrackId = dropPosition.isNewTrack ? undefined : dropPosition.trackId;
  let forceNewTrack = dropPosition.isNewTrack;
  let timeOffset = 0;

  for (const generationData of generationItems) {
    const trackIdsBeforeDrop = new Set(dataRef.current.tracks.map((track) => track.id));
    const assetId = registerGenerationAsset(generationData);

    if (!assetId) {
      continue;
    }

    if (isVideoGeneration(generationData)) {
      const existingEntry = dataRef.current.registry.assets[assetId];
      if (existingEntry) {
        patchRegistry(assetId, {
          ...existingEntry,
          duration: getDroppedGenerationDuration(generationData),
        }, generationData.imageUrl);
      }
    }

    dropAsset(
      assetId,
      targetTrackId,
      dropPosition.time + timeOffset,
      forceNewTrack,
      forceNewTrack ? insertAtTop : false,
    );

    timeOffset += getDroppedGenerationDuration(generationData);

    if (!forceNewTrack || !dataRef.current) {
      continue;
    }

    const createdTrackId = dataRef.current.tracks.find((track) => !trackIdsBeforeDrop.has(track.id))?.id
      ?? (insertAtTop ? dataRef.current.tracks[0]?.id : dataRef.current.tracks[dataRef.current.tracks.length - 1]?.id);
    if (createdTrackId) {
      targetTrackId = createdTrackId;
    }
    forceNewTrack = false;
  }

  return true;

import { useCallback, useEffect, useRef, useState, type MutableRefObject } from 'react';
import { useMutation } from '@tanstack/react-query';
import {
  isTimelineNotFoundError,
  isTimelineVersionConflictError,
  type DataProvider,
} from '@/tools/video-editor/data/DataProvider';
import { buildTimelineData, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineConfig } from '@/tools/video-editor/types';
import type { CommitDataOptions, ScheduleSaveFn } from '@/tools/video-editor/hooks/useTimelineCommit';

export type SaveStatus = 'saved' | 'saving' | 'dirty' | 'error';

const MAX_CONFLICT_RETRIES = 3;
const TIMELINE_SYNC_LOG_TAG = '[TimelineSync]';

type ConfigVersionUpdateSource = 'save' | 'reload' | 'conflict-retry';

interface UseTimelinePersistenceOptions {
  provider: DataProvider;
  timelineId: string;
  onSaveSuccessRef: MutableRefObject<(() => void) | null>;
  dataRef: MutableRefObject<TimelineData | null>;
  commitData: (nextData: TimelineData, options?: CommitDataOptions) => void;
  selectedClipIdRef: MutableRefObject<string | null>;
  selectedTrackIdRef: MutableRefObject<string | null>;
  editSeqRef: MutableRefObject<number>;
  savedSeqRef: MutableRefObject<number>;
  configVersionRef: MutableRefObject<number>;
  lastSavedSignatureRef: MutableRefObject<string>;
}

export interface UseTimelinePersistenceResult {
  scheduleSave: ScheduleSaveFn;
  saveStatus: SaveStatus;
  isConflictExhausted: boolean;
  reloadFromServer: () => Promise<void>;
  retrySaveAfterConflict: () => Promise<void>;
  isSavingRef: MutableRefObject<boolean>;
}

export function useTimelinePersistence({
  provider,
  timelineId,
  onSaveSuccessRef,
  dataRef,
  commitData,
  selectedClipIdRef,
  selectedTrackIdRef,
  editSeqRef,
  savedSeqRef,
  configVersionRef,
  lastSavedSignatureRef,
}: UseTimelinePersistenceOptions): UseTimelinePersistenceResult {
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const conflictRetryRef = useRef(0);
  const pendingSaveRef = useRef<{ data: TimelineData; seq: number } | null>(null);
  const isSavingRef = useRef(false);

  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  const [isConflictExhausted, setIsConflictExhausted] = useState(false);

  const logConfigVersionUpdate = useCallback((source: ConfigVersionUpdateSource, nextVersion: number) => {
    if (!import.meta.env.DEV) {
      return;
    }

    console.log(TIMELINE_SYNC_LOG_TAG, 'configVersionRef updated', {
      source,
      from: configVersionRef.current,
      to: nextVersion,
    });
  }, [configVersionRef]);

  const handleConflictExhausted = useCallback((details: {
    expectedVersion: number;
    actualVersion?: number;
    retries: number;
    reason: 'load_failed' | 'max_retries' | 'missing_local_data';
  }) => {
    console.log('[TimelineSave] conflict retries exhausted', details);
    setIsConflictExhausted(true);
    setSaveStatus('error');
  }, []);

  const saveMutation = useMutation({
    mutationFn: ({ config, expectedVersion }: { config: TimelineConfig; expectedVersion: number }) => {
      return provider.saveTimeline(timelineId, config, expectedVersion);
    },
    retry: false,
  });

  const loadConflictRetryVersion = useCallback(async (): Promise<number> => {
    const loaded = await provider.loadTimeline(timelineId);
    logConfigVersionUpdate('conflict-retry', loaded.configVersion);
    configVersionRef.current = loaded.configVersion;
    return loaded.configVersion;
  }, [configVersionRef, logConfigVersionUpdate, provider, timelineId]);

  const doSave = useCallback(async (
    nextData: TimelineData,
    seq: number,
    options?: {
      bypassQueue?: boolean;
      completedSeqRef?: { current: number | null };
    },
  ) => {
    if (isSavingRef.current && !options?.bypassQueue) {
      pendingSaveRef.current = { data: nextData, seq };
      return;
    }

    const completedSeqRef = options?.completedSeqRef ?? { current: null };

    if (!options?.bypassQueue) {
      isSavingRef.current = true;
    }
    setSaveStatus('saving');

    try {
      const expectedVersion = configVersionRef.current;
      await saveMutation.mutateAsync(
        {
          config: nextData.config,
          expectedVersion,
        },
        {
          onSuccess: (nextVersion) => {
            logConfigVersionUpdate('save', nextVersion);
            configVersionRef.current = nextVersion;
            completedSeqRef.current = seq;

            if (conflictRetryRef.current > 0) {
              console.log('[TimelineSave] conflict retry succeeded', {
                attempts: conflictRetryRef.current,
                finalVersion: nextVersion,
              });
            }

            conflictRetryRef.current = 0;
            setIsConflictExhausted(false);

            if (dataRef.current?.signature === nextData.signature) {
              commitData({
                ...dataRef.current,
                configVersion: nextVersion,
              }, {
                save: false,
                skipHistory: true,
                selectedClipId: selectedClipIdRef.current,
                selectedTrackId: selectedTrackIdRef.current,
              });
            }

            if (seq > savedSeqRef.current) {
              savedSeqRef.current = seq;
              lastSavedSignatureRef.current = nextData.stableSignature;
            }

            setSaveStatus(seq >= editSeqRef.current ? 'saved' : 'dirty');
            onSaveSuccessRef.current?.();
          },
        },
      );
    } catch (error) {
      if (isTimelineNotFoundError(error)) {
        console.log('[TimelineSave] timeline not found, cannot save');
        handleConflictExhausted({
          expectedVersion: configVersionRef.current,
          retries: conflictRetryRef.current,
          reason: 'missing_local_data',
        });
        return;
      }

      if (isTimelineVersionConflictError(error)) {
        const expectedVersion = configVersionRef.current;
        let actualVersion: number | undefined;

        try {
          actualVersion = await loadConflictRetryVersion();
          console.log('[TimelineSave] conflict detected', {
            expectedVersion,
            actualVersion,
          });
        } catch {
          handleConflictExhausted({
            expectedVersion,
            retries: conflictRetryRef.current,
            reason: 'load_failed',
          });
          return;
        }

        if (!dataRef.current) {
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'missing_local_data',
          });
          return;
        }

        if (actualVersion === expectedVersion) {
          console.log('[TimelineSave] reloaded version matches expected — not a version race', {
            expectedVersion,
            actualVersion,
          });
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'max_retries',
          });
          return;
        }

        if (conflictRetryRef.current >= MAX_CONFLICT_RETRIES) {
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'max_retries',
          });
          return;
        }

        conflictRetryRef.current += 1;
        console.log('[TimelineSave] retrying save after conflict', {
          attempt: conflictRetryRef.current,
          expectedVersion,
          actualVersion,
        });
        return await doSave(dataRef.current, editSeqRef.current, {
          bypassQueue: true,
          completedSeqRef,
        });
      }

      setSaveStatus('error');
      if (dataRef.current) {
        scheduleSave(dataRef.current, { preserveStatus: true });
      }
    } finally {
      if (!options?.bypassQueue) {
        isSavingRef.current = false;

        const pendingSave = pendingSaveRef.current;
        if (pendingSave) {
          pendingSaveRef.current = null;
          if (completedSeqRef.current === null || pendingSave.seq > completedSeqRef.current) {
            void doSave(pendingSave.data, pendingSave.seq);
          }
        }
      }
    }
  }, [
    commitData,
    configVersionRef,
    dataRef,
    editSeqRef,
    handleConflictExhausted,
    lastSavedSignatureRef,
    loadConflictRetryVersion,
    logConfigVersionUpdate,
    onSaveSuccessRef,
    saveMutation,
    savedSeqRef,
    selectedClipIdRef,
    selectedTrackIdRef,
  ]);

  const scheduleSave = useCallback<ScheduleSaveFn>((nextData, options) => {
    if (!options?.preserveStatus) {
      setSaveStatus('dirty');
    }

    if (saveTimer.current) {
      clearTimeout(saveTimer.current);
    }

    saveTimer.current = setTimeout(() => {
      saveTimer.current = null;
      conflictRetryRef.current = 0;
      void doSave(nextData, editSeqRef.current);
    }, 500);
  }, [doSave, editSeqRef]);

  const reloadFromServer = useCallback(async () => {
    const [loadedTimeline, registry] = await Promise.all([
      provider.loadTimeline(timelineId),
      provider.loadAssetRegistry(timelineId),
    ]);

    conflictRetryRef.current = 0;
    pendingSaveRef.current = null;
    setIsConflictExhausted(false);
    editSeqRef.current = savedSeqRef.current;
    logConfigVersionUpdate('reload', loadedTimeline.configVersion);
    configVersionRef.current = loadedTimeline.configVersion;

    commitData(
      await buildTimelineData(
        loadedTimeline.config,
        registry,
        (file) => provider.resolveAssetUrl(file),
        loadedTimeline.configVersion,
      ),
      {
        save: false,
        skipHistory: true,
        updateLastSavedSignature: true,
        selectedClipId: selectedClipIdRef.current,
        selectedTrackId: selectedTrackIdRef.current,
      },
    );
    setSaveStatus('saved');
  }, [
    commitData,
    configVersionRef,
    editSeqRef,
    logConfigVersionUpdate,
    provider,
    savedSeqRef,
    selectedClipIdRef,
    selectedTrackIdRef,
    timelineId,
  ]);

  const retrySaveAfterConflict = useCallback(async () => {
    if (!dataRef.current) {
      return;
    }

    setIsConflictExhausted(false);
    setSaveStatus('saving');
    conflictRetryRef.current = 0;

    try {
      await loadConflictRetryVersion();
      if (dataRef.current) {
        void doSave(dataRef.current, editSeqRef.current);
      }
    } catch {
      handleConflictExhausted({
        expectedVersion: configVersionRef.current,
        retries: conflictRetryRef.current,
        reason: 'load_failed',
      });
    }
  }, [configVersionRef, dataRef, doSave, editSeqRef, handleConflictExhausted, loadConflictRetryVersion]);

  useEffect(() => {
    return () => {
      if (saveTimer.current) {
        clearTimeout(saveTimer.current);
      }
    };
  }, []);

  return {
    scheduleSave,
    saveStatus,
    isConflictExhausted,
    reloadFromServer,
    retrySaveAfterConflict,
    isSavingRef,
  };
}

import { useCallback } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import { getGenerationDropData } from '@/shared/lib/dnd/dragDrop';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import { generateClientThumbnail, uploadImageWithThumbnail } from '@/shared/media/clientThumbnailGenerator';
import { createExternalUploadGeneration } from '@/integrations/supabase/repositories/generationMutationsRepository';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { getCompatibleTrackId, updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getTrackIndex } from '@/tools/video-editor/lib/editor-utils';
import {
  getNextClipId,
  inferTrackType,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData.types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry, ClipType } from '@/tools/video-editor/types';

export interface UseAssetManagementArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  selectedTrackId: string | null;
  selectedProjectId: string | null;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyEdit: UseTimelineDataResult['applyEdit'];
  patchRegistry: UseTimelineDataResult['patchRegistry'];
  registerAsset: UseTimelineDataResult['registerAsset'];
  uploadAsset: UseTimelineDataResult['uploadAsset'];
  invalidateAssetRegistry: UseTimelineDataResult['invalidateAssetRegistry'];
  resolveAssetUrl: (file: string) => Promise<string>;
}

export interface UseAssetManagementResult {
  registerGenerationAsset: (data: ReturnType<typeof getGenerationDropData>) => string | null;
  uploadImageGeneration: (file: File) => Promise<{
    generationId: string;
    variantType: 'image';
    imageUrl: string;
    thumbUrl: string;
    metadata: {
      content_type: string;
      original_filename: string;
    };
  }>;
  handleAssetDrop: (assetKey: string, trackId: string | undefined, time: number, forceNewTrack?: boolean, insertAtTop?: boolean) => void;
}

export function useAssetManagement({
  dataRef,
  selectedTrackId,
  selectedProjectId,
  setSelectedClipId,
  setSelectedTrackId,
  applyEdit,
  patchRegistry,
  registerAsset,
}: UseAssetManagementArgs): UseAssetManagementResult {
  const registerGenerationAsset = useCallback((generationData: ReturnType<typeof getGenerationDropData>) => {
    if (!generationData) {
      return null;
    }

    const mimeType = (() => {
      const metadataContentType = typeof generationData.metadata?.content_type === 'string'
        ? generationData.metadata.content_type
        : null;
      if (metadataContentType?.includes('/')) {
        return metadataContentType;
      }
      if (metadataContentType === 'video' || generationData.variantType === 'video' || /\.(mp4|mov|webm|m4v)$/i.test(generationData.imageUrl)) {
        return 'video/mp4';
      }
      if (metadataContentType === 'audio' || /\.(mp3|wav|aac|m4a)$/i.test(generationData.imageUrl)) {
        return 'audio/mpeg';
      }
      return 'image/png';
    })();

    const assetId = generateUUID();
    const entry: AssetRegistryEntry = {
      file: generationData.imageUrl,
      type: mimeType,
      generationId: generationData.generationId,
      variantId: generationData.variantId,
    };

    patchRegistry(assetId, entry, generationData.imageUrl);
    void registerAsset(assetId, entry).catch((error) => {
      console.error('[video-editor] Failed to persist generation asset:', error);
    });

    return assetId;
  }, [patchRegistry, registerAsset]);

  const uploadImageGeneration = useCallback(async (file: File) => {
    if (!selectedProjectId) {
      throw new Error('External image drop requires a selected project');
    }

    let imageUrl = '';
    let thumbnailUrl = '';

    try {
      const thumbnailResult = await generateClientThumbnail(file, 300, 0.8);
      const uploadResult = await uploadImageWithThumbnail(file, thumbnailResult.thumbnailBlob);
      imageUrl = uploadResult.imageUrl;
      thumbnailUrl = uploadResult.thumbnailUrl;
    } catch (error) {
      normalizeAndPresentError(error, { context: `video-editor:external-drop:${file.name}`, showToast: false });
      imageUrl = await uploadImageToStorage(file, 3);
      thumbnailUrl = imageUrl;
    }

    const generation = await createExternalUploadGeneration({
      imageUrl,
      thumbnailUrl,
      fileType: 'image',
      projectId: selectedProjectId,
      generationParams: {
        prompt: `Uploaded ${file.name}`,
        extra: {
          source: 'external_upload',
          original_filename: file.name,
          file_type: file.type || 'image',
          file_size: file.size,
        },
      },
    });

    return {
      generationId: generation.id,
      variantType: 'image' as const,
      imageUrl,
      thumbUrl: thumbnailUrl,
      metadata: {
        content_type: file.type || 'image',
        original_filename: file.name,
      },
    };
  }, [selectedProjectId]);

  const handleAssetDrop = useCallback((assetKey: string, trackId: string | undefined, time: number, forceNewTrack = false, insertAtTop = false) => {
    let current = dataRef.current;
    if (!current) {
      return;
    }

    const assetEntry = current.registry.assets[assetKey];
    const assetKind = inferTrackType(assetEntry?.file ?? assetKey);
    let resolvedTrackId = forceNewTrack
      ? null
      : getCompatibleTrackId(current.tracks, trackId, assetKind, selectedTrackId);

    // If no compatible track exists (or forced new track), create one immutably
    if (!resolvedTrackId) {
      const prefix = assetKind === 'audio' ? 'A' : 'V';
      const nextNumber = getTrackIndex(current.tracks, prefix) + 1;
      resolvedTrackId = `${prefix}${nextNumber}`;
      const newTrack = {
        id: resolvedTrackId,
        kind: assetKind,
        label: `${prefix}${nextNumber}`,
      };
      current = {
        ...current,
        tracks: insertAtTop ? [newTrack, ...current.tracks] : [...current.tracks, newTrack],
        rows: insertAtTop ? [{ id: resolvedTrackId, actions: [] }, ...current.rows] : [...current.rows, { id: resolvedTrackId, actions: [] }],
      };
      dataRef.current = current;
    }

    const track = current.tracks.find((candidate) => candidate.id === resolvedTrackId);
    if (!track) {
      return;
    }

    const clipId = getNextClipId(current.meta);
    const isImage = assetEntry?.type?.startsWith('image');
    const isVideo = assetEntry?.type?.startsWith('video') || (!isImage && assetKind === 'visual' && assetEntry?.duration);
    const isManual = track.fit === 'manual';
    const clipType: ClipType = isImage ? 'hold' : 'media';
    // Use actual asset duration for videos/audio instead of capping at 5s
    const baseDuration = isVideo
      ? (assetEntry?.duration ?? 5)
      : isImage
        ? 5
        : Math.max(1, assetEntry?.duration ?? 5);

    let clipMeta: ClipMeta;
    let duration: number;

    if (track.kind === 'audio') {
      duration = assetEntry?.duration ?? 10;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType: 'media',
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
      };
    } else if (isImage) {
      duration = 5;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        hold: duration,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    } else {
      duration = baseDuration;
      clipMeta = {
        asset: assetKey,
        track: resolvedTrackId,
        clipType,
        from: 0,
        to: duration,
        speed: 1,
        volume: 1,
        opacity: 1,
        x: isManual ? 100 : undefined,
        y: isManual ? 100 : undefined,
        width: isManual ? 320 : undefined,
        height: isManual ? 240 : undefined,
      };
    }

    const action: TimelineAction = {
      id: clipId,
      start: time,
      end: time + duration,
      effectId: `effect-${clipId}`,
    };

    const nextRows = current.rows.map((row) => (row.id === resolvedTrackId ? { ...row, actions: [...row.actions, action] } : row));
    const nextClipOrder = updateClipOrder(current.clipOrder, resolvedTrackId, (ids) => [...ids, clipId]);
    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [clipId]: clipMeta },
      clipOrderOverride: nextClipOrder,
    });
    setSelectedClipId(clipId);
    setSelectedTrackId(resolvedTrackId);
  }, [applyEdit, dataRef, selectedTrackId, setSelectedClipId, setSelectedTrackId]);

  return {
    registerGenerationAsset,
    uploadImageGeneration,
    handleAssetDrop,
  };
}

    const next = { ...current };
    delete next[actionId];
    return next;
  });
}, []);

const getResizeContext = useCallback((actionId: string, rowId: string) => {
  const row = rows.find((candidate) => candidate.id === rowId);
  const action = row?.actions.find((candidate) => candidate.id === actionId);
  if (!row || !action) {
    return null;
  }

  const override = resizePreviewRef.current[actionId] ?? resizeOverrides[actionId];
  return {
    row,
    action: override ? { ...action, ...override } : action,
  };
}, [resizeOverrides, rows]);

const updateResize = useCallback((session: ResizeSession, clientX: number) => {
  const deltaSeconds = (clientX - session.initialClientX) / pixelsPerSecond;
  let start = session.dir === 'left'
    ? clamp(session.initialStart + deltaSeconds, 0, session.initialEnd - minDuration)
    : session.initialStart;
  let end = session.dir === 'right'
    ? Math.max(session.initialStart + minDuration, session.initialEnd + deltaSeconds)
    : session.initialEnd;

  // Snap the resizing edge to sibling clip edges
  const row = rows.find((r) => r.id === session.rowId);
  if (row) {
    const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
    const snapped = snapResize(start, end, session.dir, row.actions, session.actionId, snapThresholdS);
    start = snapped.start;
    end = snapped.end;
  }

  // Re-enforce min duration after snap
  if (end - start < minDuration) {
    if (session.dir === 'left') {
      start = end - minDuration;
    } else {
      end = start + minDuration;
    }
  }

  const context = getResizeContext(session.actionId, session.rowId);
  if (!context) {
    return;
  }

  const nextAction = {
    ...context.action,
    start,
    end,
  };

  resizePreviewRef.current[session.actionId] = { start, end };
  setResizeOverrides((current) => ({
    ...current,
    [session.actionId]: { start, end },
  }));
  onActionResizing?.({
    action: nextAction,
    row: context.row,
    start,
    end,
    dir: session.dir,
  });
}, [getResizeContext, minDuration, onActionResizing, pixelsPerSecond, rows]);

const endResize = useCallback((event: ReactPointerEvent<HTMLDivElement>, cancelled: boolean) => {
  const session = resizeSessionRef.current;
  if (!session || session.pointerId !== event.pointerId) {
    return;
  }

  resizeSessionRef.current = null;
  if (event.currentTarget.hasPointerCapture(event.pointerId)) {
    event.currentTarget.releasePointerCapture(event.pointerId);
  }

  const context = getResizeContext(session.actionId, session.rowId);
  if (!cancelled && context) {
    onActionResizeEnd?.({
      action: context.action,
      row: context.row,
      start: context.action.start,
      end: context.action.end,
      dir: session.dir,
    });
  }

  clearResizeOverride(session.actionId);
}, [clearResizeOverride, getResizeContext, onActionResizeEnd]);

const handleResizePointerDown = useCallback((
  event: ReactPointerEvent<HTMLDivElement>,
  action: TimelineAction,
  row: TimelineRow,
  dir: ResizeDir,
) => {
  if (event.button !== 0) {
    return;
  }

  resizeSessionRef.current = {
    pointerId: event.pointerId,
    actionId: action.id,
    rowId: row.id,
    dir,
    initialStart: action.start,
    initialEnd: action.end,
    initialClientX: event.clientX,
  };
  resizePreviewRef.current[action.id] = {
    start: action.start,
    end: action.end,
  };
  setResizeOverrides((current) => ({
    ...current,
    [action.id]: {
      start: action.start,
      end: action.end,
    },
  }));
  onActionResizeStart?.({ action, row, dir });
  event.currentTarget.setPointerCapture(event.pointerId);
  event.preventDefault();
  event.stopPropagation();

  syncCursor();
  onScroll?.(nextMetrics);
};

const clearResizeOverride = useCallback((actionId: string) => {
  delete resizePreviewRef.current[actionId];
  setResizeOverrides((current) => {
    if (!(actionId in current)) {
      return current;
    }

    const next = { ...current };
    delete next[actionId];
    return next;
  });
}, []);

