                  {badge}
                </span>
              ))}
            </div>
          )}
        </div>
        {isVariantStale && (
          <div
            className="absolute right-1 top-1 flex h-4 w-4 cursor-pointer items-center justify-center rounded-full bg-amber-500 text-white hover:bg-amber-400"
            title="Variant outdated"
            role="button"
            onClick={(e) => {
              e.stopPropagation();
