  });

  useLayoutEffect(() => {
    scheduleSaveRef.current = persistence.scheduleSave;
  }, [persistence.scheduleSave]);

  usePollSync({
    queries,
    provider,
    commitData: commit.commitData,
    dataRef: commit.dataRef,
    selectedClipIdRef: commit.selectedClipIdRef,
    selectedTrackIdRef: commit.selectedTrackIdRef,
    editSeqRef: commit.editSeqRef,
    pendingOpsRef: commit.pendingOpsRef,
    savedSeqRef,
    configVersionRef,
    lastSavedSignatureRef,
    isSavingRef: persistence.isSavingRef,
  });

  return {
    data: commit.data,
    dataRef: commit.dataRef,
    isConflictExhausted: persistence.isConflictExhausted,
    selectedClipId: commit.selectedClipId,
    selectedTrackId: commit.selectedTrackId,
    saveStatus: persistence.saveStatus,
    setSelectedClipId: commit.setSelectedClipId,
    setSelectedTrackId: commit.setSelectedTrackId,
    applyEdit: commit.applyEdit,
    patchRegistry: commit.patchRegistry,
    commitData: commit.commitData,
    onBeforeCommitRef: commit.onBeforeCommitRef,
    reloadFromServer: persistence.reloadFromServer,
    retrySaveAfterConflict: persistence.retrySaveAfterConflict,
    editSeqRef: commit.editSeqRef,
    pendingOpsRef: commit.pendingOpsRef,
    savedSeqRef,
    selectedClipIdRef: commit.selectedClipIdRef,
    selectedTrackIdRef: commit.selectedTrackIdRef,
    isLoading: queries.timelineQuery.isLoading && !commit.data,
  };
}

import {
  useCallback,
  useLayoutEffect,
  useRef,
  useState,
  type Dispatch,
  type MutableRefObject,
  type SetStateAction,
} from 'react';
import { buildTrackClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { migrateToFlatTracks } from '@/tools/video-editor/lib/migrate';
import { serializeForDisk } from '@/tools/video-editor/lib/serialize';
import { buildDataFromCurrentRegistry } from '@/tools/video-editor/lib/timeline-save-utils';
import {
  assembleTimelineData,
  preserveUploadingClips,
  rowsToConfig,
  type ClipMeta,
  type ClipOrderMap,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry } from '@/tools/video-editor/types';

export type CommitHistoryOptions = {
  transactionId?: string;
  semantic?: boolean;
};

export type CommitDataOptions = {
  save?: boolean;
  selectedClipId?: string | null;
  selectedTrackId?: string | null;
  updateLastSavedSignature?: boolean;
  transactionId?: string;
  semantic?: boolean;
  skipHistory?: boolean;
};

export type ScheduleSaveFn = (
  nextData: TimelineData,
  options?: { preserveStatus?: boolean },
) => void;

export type TimelineEditMutation =
  | {
      type: 'rows';
      rows: TimelineRow[];
      metaUpdates?: Record<string, Partial<ClipMeta>>;
      metaDeletes?: string[];
      clipOrderOverride?: ClipOrderMap;
    }
  | {
      type: 'config';
      resolvedConfig: TimelineData['resolvedConfig'];
    };

export type ApplyEditOptions = {
  save?: boolean;
  selectedClipId?: string | null;
  selectedTrackId?: string | null;
  transactionId?: string;
  semantic?: boolean;
};

interface UseTimelineCommitOptions {
  pruneSelectionRef: MutableRefObject<((validIds: Set<string>) => void) | null>;
  scheduleSaveRef: MutableRefObject<ScheduleSaveFn>;
  lastSavedSignatureRef: MutableRefObject<string>;
}

export interface UseTimelineCommitResult {
  data: TimelineData | null;
  dataRef: MutableRefObject<TimelineData | null>;
  selectedClipId: string | null;
  selectedTrackId: string | null;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyEdit: (mutation: TimelineEditMutation, options?: ApplyEditOptions) => void;
  patchRegistry: (assetId: string, entry: AssetRegistryEntry, src?: string) => void;
  commitData: (nextData: TimelineData, options?: CommitDataOptions) => void;
  materializeData: (
    current: TimelineData,
    rows: TimelineRow[],
    meta: Record<string, ClipMeta>,
    clipOrder: ClipOrderMap,
  ) => TimelineData;
  onBeforeCommitRef: MutableRefObject<((currentData: TimelineData, options: CommitHistoryOptions) => void) | null>;
  editSeqRef: MutableRefObject<number>;
  pendingOpsRef: MutableRefObject<number>;
  selectedClipIdRef: MutableRefObject<string | null>;
  selectedTrackIdRef: MutableRefObject<string | null>;
}

export function useTimelineCommit({
  pruneSelectionRef,
  scheduleSaveRef,
  lastSavedSignatureRef,
}: UseTimelineCommitOptions): UseTimelineCommitResult {
  const editSeqRef = useRef(0);
  const pendingOpsRef = useRef(0);
  const dataRef = useRef<TimelineData | null>(null);
  const selectedClipIdRef = useRef<string | null>(null);
  const selectedTrackIdRef = useRef<string | null>(null);
  const onBeforeCommitRef = useRef<((currentData: TimelineData, options: CommitHistoryOptions) => void) | null>(null);

  const [data, setData] = useState<TimelineData | null>(null);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);

  useLayoutEffect(() => {
    dataRef.current = data;
    selectedClipIdRef.current = selectedClipId;
    selectedTrackIdRef.current = selectedTrackId;
  }, [data, selectedClipId, selectedTrackId]);

  const materializeData = useCallback((
    current: TimelineData,
    rows: TimelineRow[],
    meta: Record<string, ClipMeta>,
    clipOrder: ClipOrderMap,
  ) => {
    const config = rowsToConfig(
      rows,
      meta,
      current.output,
      clipOrder,
      current.tracks,
      current.config.customEffects,
    );

    return preserveUploadingClips(
      { ...current, rows, meta } as TimelineData,
      buildDataFromCurrentRegistry(config, current),
    );
  }, []);

  const commitData = useCallback((
    nextData: TimelineData,
    options?: CommitDataOptions,
  ) => {
    const shouldSave = options?.save ?? true;
    const currentData = dataRef.current;

    if (shouldSave && !options?.skipHistory && currentData) {
      onBeforeCommitRef.current?.(currentData, {
        transactionId: options?.transactionId,
        semantic: options?.semantic,
      });
    }

    dataRef.current = nextData;
    setData(nextData);

    if (options?.selectedClipId !== undefined) {
      selectedClipIdRef.current = options.selectedClipId;
      setSelectedClipId(options.selectedClipId);
    } else if (selectedClipIdRef.current && !nextData.meta[selectedClipIdRef.current]) {
      selectedClipIdRef.current = null;
      setSelectedClipId(null);
    }

    pruneSelectionRef.current?.(new Set(Object.keys(nextData.meta)));

    if (options?.selectedTrackId !== undefined) {
      selectedTrackIdRef.current = options.selectedTrackId;
      setSelectedTrackId(options.selectedTrackId);
    } else {
      const fallbackTrackId = selectedTrackIdRef.current
        && nextData.tracks.some((track) => track.id === selectedTrackIdRef.current)
        ? selectedTrackIdRef.current
        : nextData.tracks[0]?.id ?? null;
      selectedTrackIdRef.current = fallbackTrackId;
      setSelectedTrackId(fallbackTrackId);
    }

    if (options?.updateLastSavedSignature) {
      lastSavedSignatureRef.current = nextData.stableSignature;
    }

    if (shouldSave) {
      editSeqRef.current += 1;
      scheduleSaveRef.current(nextData);
    }
  }, [lastSavedSignatureRef, pruneSelectionRef, scheduleSaveRef]);

  const applyEdit = useCallback((
    mutation: TimelineEditMutation,
    options?: ApplyEditOptions,
  ) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    if (mutation.type === 'rows') {
      const nextMeta: Record<string, ClipMeta> = { ...current.meta };

      if (mutation.metaUpdates) {
        for (const [clipId, patch] of Object.entries(mutation.metaUpdates)) {
          nextMeta[clipId] = nextMeta[clipId]
            ? { ...nextMeta[clipId], ...patch }
            : (patch as ClipMeta);
        }
      }

      if (mutation.metaDeletes) {
        for (const clipId of mutation.metaDeletes) {
          delete nextMeta[clipId];
        }
      }

      commitData(
        materializeData(
          current,
          mutation.rows,
          nextMeta,
          mutation.clipOrderOverride ?? buildTrackClipOrder(current.tracks, current.clipOrder, mutation.metaDeletes),
        ),
        {
          save: options?.save,
          transactionId: options?.transactionId,
          semantic: options?.semantic,
        },
      );
      return;
    }

    commitData(
      preserveUploadingClips(current, buildDataFromCurrentRegistry(serializeForDisk(mutation.resolvedConfig), current)),
      {
        save: options?.save,
        selectedClipId: options?.selectedClipId,
        selectedTrackId: options?.selectedTrackId,
        transactionId: options?.transactionId,
        semantic: options?.semantic,
      },
    );
  }, [commitData, materializeData]);

  const patchRegistry = useCallback((assetId: string, entry: AssetRegistryEntry, src?: string) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const nextRegistry = {
      ...current.registry,
      assets: {
        ...current.registry.assets,
        [assetId]: entry,
      },
    };
    const nextResolvedRegistry = {
      ...current.resolvedConfig.registry,
      [assetId]: {
        ...entry,
        src: src ?? current.resolvedConfig.registry[assetId]?.src ?? entry.file,
      },
    };
    const nextConfig = {
      ...current.config,
      customEffects: current.config.customEffects
        ? { ...current.config.customEffects }
        : undefined,
    };
    const migratedConfig = migrateToFlatTracks(nextConfig);
    migratedConfig.tracks = migratedConfig.tracks ?? [];

    const nextData = assembleTimelineData({
      config: migratedConfig,
      configVersion: current.configVersion,
      registry: nextRegistry,
      resolvedConfig: {
        output: { ...migratedConfig.output },
        tracks: migratedConfig.tracks,
        clips: migratedConfig.clips.map((clip) => ({
          ...clip,
          assetEntry: clip.asset ? nextResolvedRegistry[clip.asset] : undefined,
        })),
        // Reuse resolved entries for unchanged assets and patch the current asset in-place.
        registry: nextResolvedRegistry,
      },
      assetMap: Object.fromEntries(
        Object.entries(nextRegistry.assets ?? {}).map(([nextAssetId, nextEntry]) => [nextAssetId, nextEntry.file]),
      ),
      output: { ...migratedConfig.output },
    });

    commitData(nextData, {
      save: false,
      selectedClipId: selectedClipIdRef.current,
      selectedTrackId: selectedTrackIdRef.current,
    });
  }, [commitData]);

  return {
    data,
    dataRef,
    selectedClipId,
    selectedTrackId,
    setSelectedClipId,
    setSelectedTrackId,
    applyEdit,
    patchRegistry,
    commitData,
    materializeData,
    onBeforeCommitRef,
    editSeqRef,
    pendingOpsRef,
    selectedClipIdRef,
    selectedTrackIdRef,
  };
}

import { useCallback, useEffect, useRef, useState, type MutableRefObject } from 'react';
import { useMutation } from '@tanstack/react-query';
import {
  isTimelineNotFoundError,
  isTimelineVersionConflictError,
  type DataProvider,
} from '@/tools/video-editor/data/DataProvider';
import { buildTimelineData, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineConfig } from '@/tools/video-editor/types';
import type { CommitDataOptions, ScheduleSaveFn } from '@/tools/video-editor/hooks/useTimelineCommit';

export type SaveStatus = 'saved' | 'saving' | 'dirty' | 'error';

const MAX_CONFLICT_RETRIES = 3;
const TIMELINE_SYNC_LOG_TAG = '[TimelineSync]';

type ConfigVersionUpdateSource = 'save' | 'reload' | 'conflict-retry';

interface UseTimelinePersistenceOptions {
  provider: DataProvider;
  timelineId: string;
  onSaveSuccessRef: MutableRefObject<(() => void) | null>;
  dataRef: MutableRefObject<TimelineData | null>;
  commitData: (nextData: TimelineData, options?: CommitDataOptions) => void;
  selectedClipIdRef: MutableRefObject<string | null>;
  selectedTrackIdRef: MutableRefObject<string | null>;
  editSeqRef: MutableRefObject<number>;
  savedSeqRef: MutableRefObject<number>;
  configVersionRef: MutableRefObject<number>;
  lastSavedSignatureRef: MutableRefObject<string>;
}

export interface UseTimelinePersistenceResult {
  scheduleSave: ScheduleSaveFn;
  saveStatus: SaveStatus;
  isConflictExhausted: boolean;
  reloadFromServer: () => Promise<void>;
  retrySaveAfterConflict: () => Promise<void>;
  isSavingRef: MutableRefObject<boolean>;
}

export function useTimelinePersistence({
  provider,
  timelineId,
  onSaveSuccessRef,
  dataRef,
  commitData,
  selectedClipIdRef,
  selectedTrackIdRef,
  editSeqRef,
  savedSeqRef,
  configVersionRef,
  lastSavedSignatureRef,
}: UseTimelinePersistenceOptions): UseTimelinePersistenceResult {
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const conflictRetryRef = useRef(0);
  const pendingSaveRef = useRef<{ data: TimelineData; seq: number } | null>(null);
  const isSavingRef = useRef(false);

  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  const [isConflictExhausted, setIsConflictExhausted] = useState(false);

  const logConfigVersionUpdate = useCallback((source: ConfigVersionUpdateSource, nextVersion: number) => {
    if (!import.meta.env.DEV) {
      return;
    }

    console.log(TIMELINE_SYNC_LOG_TAG, 'configVersionRef updated', {
      source,
      from: configVersionRef.current,
      to: nextVersion,
    });
  }, [configVersionRef]);

  const handleConflictExhausted = useCallback((details: {
    expectedVersion: number;
    actualVersion?: number;
    retries: number;
    reason: 'load_failed' | 'max_retries' | 'missing_local_data';
  }) => {
    console.log('[TimelineSave] conflict retries exhausted', details);
    setIsConflictExhausted(true);
    setSaveStatus('error');
  }, []);

  const saveMutation = useMutation({
    mutationFn: ({ config, expectedVersion }: { config: TimelineConfig; expectedVersion: number }) => {
      return provider.saveTimeline(timelineId, config, expectedVersion);
    },
    retry: false,
  });

  const loadConflictRetryVersion = useCallback(async (): Promise<number> => {
    const loaded = await provider.loadTimeline(timelineId);
    logConfigVersionUpdate('conflict-retry', loaded.configVersion);
    configVersionRef.current = loaded.configVersion;
    return loaded.configVersion;
  }, [configVersionRef, logConfigVersionUpdate, provider, timelineId]);

  const doSave = useCallback(async (
    nextData: TimelineData,
    seq: number,
    options?: {
      bypassQueue?: boolean;
      completedSeqRef?: { current: number | null };
    },
  ) => {
    if (isSavingRef.current && !options?.bypassQueue) {
      pendingSaveRef.current = { data: nextData, seq };
      return;
    }

    const completedSeqRef = options?.completedSeqRef ?? { current: null };

    if (!options?.bypassQueue) {
      isSavingRef.current = true;
    }
    setSaveStatus('saving');

    try {
      const expectedVersion = configVersionRef.current;
      await saveMutation.mutateAsync(
        {
          config: nextData.config,
          expectedVersion,
        },
        {
          onSuccess: (nextVersion) => {
            logConfigVersionUpdate('save', nextVersion);
            configVersionRef.current = nextVersion;
            completedSeqRef.current = seq;

            if (conflictRetryRef.current > 0) {
              console.log('[TimelineSave] conflict retry succeeded', {
                attempts: conflictRetryRef.current,
                finalVersion: nextVersion,
              });
            }

            conflictRetryRef.current = 0;
            setIsConflictExhausted(false);

            if (dataRef.current?.signature === nextData.signature) {
              commitData({
                ...dataRef.current,
                configVersion: nextVersion,
              }, {
                save: false,
                skipHistory: true,
                selectedClipId: selectedClipIdRef.current,
                selectedTrackId: selectedTrackIdRef.current,
              });
            }

            if (seq > savedSeqRef.current) {
              savedSeqRef.current = seq;
              lastSavedSignatureRef.current = nextData.stableSignature;
            }

            setSaveStatus(seq >= editSeqRef.current ? 'saved' : 'dirty');
            onSaveSuccessRef.current?.();
          },
        },
      );
    } catch (error) {
      if (isTimelineNotFoundError(error)) {
        console.log('[TimelineSave] timeline not found, cannot save');
        handleConflictExhausted({
          expectedVersion: configVersionRef.current,
          retries: conflictRetryRef.current,
          reason: 'missing_local_data',
        });
        return;
      }

      if (isTimelineVersionConflictError(error)) {
        const expectedVersion = configVersionRef.current;
        let actualVersion: number | undefined;

        try {
          actualVersion = await loadConflictRetryVersion();
          console.log('[TimelineSave] conflict detected', {
            expectedVersion,
            actualVersion,
          });
        } catch {
          handleConflictExhausted({
            expectedVersion,
            retries: conflictRetryRef.current,
            reason: 'load_failed',
          });
          return;
        }

        if (!dataRef.current) {
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'missing_local_data',
          });
          return;
        }

        if (actualVersion === expectedVersion) {
          console.log('[TimelineSave] reloaded version matches expected — not a version race', {
            expectedVersion,
            actualVersion,
          });
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'max_retries',
          });
          return;
        }

        if (conflictRetryRef.current >= MAX_CONFLICT_RETRIES) {
          handleConflictExhausted({
            expectedVersion,
            actualVersion,
            retries: conflictRetryRef.current,
            reason: 'max_retries',
          });
          return;
        }

        conflictRetryRef.current += 1;
        console.log('[TimelineSave] retrying save after conflict', {
          attempt: conflictRetryRef.current,
          expectedVersion,
          actualVersion,
        });
        return await doSave(dataRef.current, editSeqRef.current, {
          bypassQueue: true,
          completedSeqRef,
        });
      }

      setSaveStatus('error');
      if (dataRef.current) {
        scheduleSave(dataRef.current, { preserveStatus: true });
      }
    } finally {
      if (!options?.bypassQueue) {
        isSavingRef.current = false;

        const pendingSave = pendingSaveRef.current;
        if (pendingSave) {
          pendingSaveRef.current = null;
          if (completedSeqRef.current === null || pendingSave.seq > completedSeqRef.current) {
            void doSave(pendingSave.data, pendingSave.seq);
          }
        }
      }
    }
  }, [
    commitData,
    configVersionRef,
    dataRef,
    editSeqRef,
    handleConflictExhausted,
    lastSavedSignatureRef,
    loadConflictRetryVersion,
    logConfigVersionUpdate,
    onSaveSuccessRef,
    saveMutation,
    savedSeqRef,
    selectedClipIdRef,
    selectedTrackIdRef,
  ]);

  const scheduleSave = useCallback<ScheduleSaveFn>((nextData, options) => {
    if (!options?.preserveStatus) {
      setSaveStatus('dirty');
    }

    if (saveTimer.current) {
      clearTimeout(saveTimer.current);
    }

    saveTimer.current = setTimeout(() => {
      saveTimer.current = null;
      conflictRetryRef.current = 0;
      void doSave(nextData, editSeqRef.current);
    }, 500);
  }, [doSave, editSeqRef]);

  const reloadFromServer = useCallback(async () => {
    const [loadedTimeline, registry] = await Promise.all([
      provider.loadTimeline(timelineId),
      provider.loadAssetRegistry(timelineId),
    ]);

    conflictRetryRef.current = 0;
    pendingSaveRef.current = null;
    setIsConflictExhausted(false);
    editSeqRef.current = savedSeqRef.current;
    logConfigVersionUpdate('reload', loadedTimeline.configVersion);
    configVersionRef.current = loadedTimeline.configVersion;

    commitData(
      await buildTimelineData(
        loadedTimeline.config,
        registry,
        (file) => provider.resolveAssetUrl(file),
        loadedTimeline.configVersion,
      ),
      {
        save: false,
        skipHistory: true,
        updateLastSavedSignature: true,
        selectedClipId: selectedClipIdRef.current,
        selectedTrackId: selectedTrackIdRef.current,
      },
    );
    setSaveStatus('saved');
  }, [
    commitData,
    configVersionRef,
    editSeqRef,
    logConfigVersionUpdate,
    provider,
    savedSeqRef,
    selectedClipIdRef,
    selectedTrackIdRef,
    timelineId,
  ]);

  const retrySaveAfterConflict = useCallback(async () => {
    if (!dataRef.current) {
      return;
    }

    setIsConflictExhausted(false);
    setSaveStatus('saving');
    conflictRetryRef.current = 0;

    try {
      await loadConflictRetryVersion();
      if (dataRef.current) {
        void doSave(dataRef.current, editSeqRef.current);
      }
    } catch {
      handleConflictExhausted({
        expectedVersion: configVersionRef.current,
        retries: conflictRetryRef.current,
        reason: 'load_failed',
      });
    }
  }, [configVersionRef, dataRef, doSave, editSeqRef, handleConflictExhausted, loadConflictRetryVersion]);

  useEffect(() => {
    return () => {
      if (saveTimer.current) {
        clearTimeout(saveTimer.current);
      }
    };
  }, []);

  return {
    scheduleSave,
    saveStatus,
    isConflictExhausted,
    reloadFromServer,
    retrySaveAfterConflict,
    isSavingRef,
  };
}

