            >
              <Upload className="h-3.5 w-3.5" />
              Upload
            </Button>
          </div>
          <Input
            ref={fileInputRef}
            type="file"
            multiple
            className="hidden"
            onChange={(event) => {
              const files = Array.from(event.target.files ?? []);
              if (files.length === 0) {
