function makeCoordinator(overrides: Partial<ReturnType<DragCoordinator['update']>> = {}): DragCoordinator {
  const defaultPosition = {
    time: 0,
    rowIndex: 0,
    trackId: 'V1',
    trackKind: 'visual' as const,
    trackName: 'V1',
    isNewTrack: false,
    isNewTrackTop: false,
