      clipLeft: 0,
      clipWidth: 0,
      ghostCenter: 0,
    },
  };
  const coordinator = {
    update: vi.fn(() => {
      const nextPosition = {
        ...defaultPosition,
        ...overrides,
        screenCoords: {
          ...defaultPosition.screenCoords,
          ...overrides.screenCoords,
        },
      };
      coordinator.lastPosition = nextPosition;
      return nextPosition;
    }),
    showSecondaryGhosts: vi.fn(),
    end: vi.fn(),
    lastPosition: null,
    editAreaRef: { current: null },
  } satisfies DragCoordinator;

  return coordinator;
