        const sourceUrl = await resolveAssetUrl(result.entry.file);
        patchRegistry(result.assetId, result.entry, sourceUrl);

        const current = dataRef.current;
        if (!current) {
          return;
        }

        applyEdit({
          type: 'rows',
          rows: removeAction(current.rows, skeletonId),
          metaDeletes: [skeletonId],
        });
